const TourList = ({ tours, setEditingTour }) => {
  return (
    <div className="space-y-4 pb-10">
      {tours.length === 0 ? (
        <p className="text-center text-gray-400 py-10">No items found.</p>
      ) : (
        tours.map((tour) => (
          <div 
            key={tour._id} 
            onClick={() => setEditingTour(tour)}
            className="bg-white p-3 flex items-center space-x-4 border border-gray-100 rounded-2xl shadow-sm active:scale-95 transition-transform cursor-pointer"
          >
            <div className="w-20 h-20 flex-shrink-0 rounded-xl overflow-hidden bg-indigo-50 border border-gray-50">
              {tour.imageUrl ? (
                <img src={tour.imageUrl} alt="" className="w-full h-full object-cover" />
              ) : (
                <div className="w-full h-full flex items-center justify-center text-2xl">🏝️</div>
              )}
            </div>

            <div className="flex-1 min-w-0">
              <h3 className="font-bold text-gray-800 text-base truncate">{tour.title}</h3>
              <p className="text-gray-400 text-xs mt-1">{tour.location || 'Australia'}</p>

              <div className="mt-3">
                <span className={`px-3 py-1 rounded-lg text-xs font-bold ${tour.status === 'Available' ? 'bg-emerald-500 text-white' : 'bg-red-400 text-white'}`}>
                  {tour.status === 'Available' ? `AUD ${tour.price}` : 'Sold Out'}
                </span>
              </div>
            </div>
            <div className="text-gray-300 text-xl pr-2">›</div>
          </div>
        ))
      )}
    </div>
  );
};

export default TourList;
